# Load the knowledge article data
import json

# Read the knowledge article data
with open('/tmp/result_10.json', 'r') as f:
    knowledge_articles = json.load(f)

# Filter for Mandatory Bundles article
mandatory_bundles_article = None
for article in knowledge_articles:
    if 'bundle' in article.get('title', '').lower() or 'mandatory' in article.get('title', '').lower():
        mandatory_bundles_article = article
        break

print('__RESULT__:')
if mandatory_bundles_article:
    print(json.dumps({
        'article_id': mandatory_bundles_article['id'],
        'title': mandatory_bundles_article['title'],
        'has_pulse_sim_bundle': 'PulseSim Pro' in mandatory_bundles_article['faq_answer__c']
    }))
else:
    print(json.dumps({'error': 'Mandatory bundles article not found'}))

